import React, { useState } from 'react';
import { Button, Input, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { systemService } from '../../../services/system/systemService';
import type { SystemSettingsDto } from '../../../services/system/models';
import { normalizeCodeOptional } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'system-settings';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({
  value: String(i + 1),
  label: `Tháng ${i + 1}`,
}));

const CURRENCY_OPTIONS = [
  { value: 'VND', label: 'VND — Việt Nam Đồng' },
  { value: 'USD', label: 'USD — US Dollar' },
  { value: 'EUR', label: 'EUR — Euro' },
];

const DECIMAL_OPTIONS = [
  { value: '0', label: '0' },
  { value: '1', label: '1' },
  { value: '2', label: '2' },
  { value: '3', label: '3' },
  { value: '4', label: '4' },
];

type FormErrors = Partial<Record<'companyName', string>>;

const SystemSettingsPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [form, setForm] = useState<SystemSettingsDto>({});
  const [errors, setErrors] = useState<FormErrors>({});
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      systemService.getSettings()
        .then(data => { if (!cancelled && data) setForm(data); })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải cài đặt', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.companyName?.trim()) next.companyName = 'Nhập tên công ty';
    return next;
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      await systemService.saveSettings(form);
      dispatch(addToast({ message: 'Lưu cài đặt hệ thống thành công', type: 'success' }));
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const setField = (key: keyof SystemSettingsDto, value: unknown) => {
    if (key === 'companyName') clearFieldError('companyName');
    setForm(f => ({ ...f, [key]: value }));
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-cog" /> Cài đặt hệ thống</h1>
        </div>
        <div className={styles.headerActions}>
          <Button
            variant="primary"
            onClick={handleSave}
            disabled={saving || loading}
            data-testid={`${TEST_ID}-save-btn`}
          >
            <i className="fas fa-save" /> {saving ? 'Đang lưu...' : 'Lưu cài đặt'}
          </Button>
        </div>
      </div>

      {loading ? (
        <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
      ) : (
        <div data-testid={`${TEST_ID}-form`}>
          <div className={styles.formCard}>
            <h3 style={{ margin: '0 0 16px' }}>Thông tin doanh nghiệp</h3>
            <div className={styles.formGrid}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-companyName`}>
                <label className={styles.label}>Tên công ty *</label>
                <Input
                  value={String(form.companyName ?? '')}
                  error={errors.companyName}
                  onChange={e => setField('companyName', e.target.value)}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-taxCode`}>
                <label className={styles.label}>Mã số thuế</label>
                <Input
                  value={String(form.taxCode ?? '')}
                  className={styles.codeInput}
                  onChange={e => setField('taxCode', normalizeCodeOptional(e.target.value) ?? '')}
                />
              </div>
              <div className={styles.field} style={{ gridColumn: '1 / -1' }} data-testid={`${TEST_ID}-field-companyAddress`}>
                <label className={styles.label}>Địa chỉ</label>
                <Input value={String(form.companyAddress ?? '')} onChange={e => setField('companyAddress', e.target.value)} />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-phone`}>
                <label className={styles.label}>Điện thoại</label>
                <Input value={String(form.phone ?? '')} onChange={e => setField('phone', e.target.value)} />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-email`}>
                <label className={styles.label}>Email</label>
                <Input type="email" value={String(form.email ?? '')} onChange={e => setField('email', e.target.value)} />
              </div>
            </div>
          </div>

          <div className={styles.formCard}>
            <h3 style={{ margin: '0 0 16px' }}>Cài đặt kế toán / tài chính</h3>
            <div className={styles.formGrid}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-fiscalYearStartMonth`}>
                <label className={styles.label}>Tháng bắt đầu năm tài chính</label>
                <Select
                  value={String(form.fiscalYearStartMonth ?? 1)}
                  onChange={e => setField('fiscalYearStartMonth', Number(e.target.value))}
                  options={MONTH_OPTIONS}
                  size="small"
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-defaultCurrency`}>
                <label className={styles.label}>Đơn vị tiền tệ mặc định</label>
                <Select
                  value={String(form.defaultCurrency ?? 'VND')}
                  onChange={e => setField('defaultCurrency', e.target.value)}
                  options={CURRENCY_OPTIONS}
                  size="small"
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-decimalPlaces`}>
                <label className={styles.label}>Số chữ số thập phân</label>
                <Select
                  value={String(form.decimalPlaces ?? 0)}
                  onChange={e => setField('decimalPlaces', Number(e.target.value))}
                  options={DECIMAL_OPTIONS}
                  size="small"
                />
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SystemSettingsPage;
